using Azure.Identity;
using Microsoft.Data.SqlClient;

// SqlClient automatically uses Entra ID Managed Identity
// when Authentication=Active Directory Managed Identity is set
var connectionString =
    "Server=myserver.database.windows.net;" +
    "Database=mydb;" +
    "Authentication=Active Directory Managed Identity;";

using var conn = new SqlConnection(connectionString);
await conn.OpenAsync();

using var cmd = new SqlCommand("SELECT TOP 5 * FROM Orders", conn);
using var reader = await cmd.ExecuteReaderAsync();
while (await reader.ReadAsync())
    Console.WriteLine(reader[0]);

resource "azurerm_linux_web_app" "api" {
  name                = "my-api-app"
  resource_group_name = azurerm_resource_group.main.name
  location            = azurerm_resource_group.main.location
  service_plan_id     = azurerm_service_plan.main.id

  identity {
    type = "SystemAssigned"
  }

  site_config {}
}

# Grant read access to Key Vault secrets
resource "azurerm_role_assignment" "kv_secrets_user" {
  scope                = azurerm_key_vault.main.id
  role_definition_name = "Key Vault Secrets User"
  principal_id         = azurerm_linux_web_app.api.identity[0].principal_id
}

# Grant read access to storage blobs
resource "azurerm_role_assignment" "blob_reader" {
  scope                = azurerm_storage_account.main.id
  role_definition_name = "Storage Blob Data Reader"
  principal_id         = azurerm_linux_web_app.api.identity[0].principal_id
}

output "app_principal_id" {
  value = azurerm_linux_web_app.api.identity[0].principal_id
}
